    "# Model names\n",
    "models = ['Random Forest', 'Gradient Boosting']\n",
    "\n",
    "# Correct variables from your code\n",
    "rmse_uber_values = [rmse_uber_rf_w, rmse_uber_gb_w]\n",
    "rmse_lyft_values = [rmse_lyft_rf_w, rmse_lyft_gb_w]\n",
    "\n",
    "r2_uber_values = [r2_uber_rf_w, r2_uber_gb_w]\n",
    "r2_lyft_values = [r2_lyft_rf_w, r2_lyft_gb_w]\n",
    "\n",
    "# Bar positions\n",
    "x = np.arange(len(models))\n",
    "width = 0.35\n",
    "\n",
    "# Create figure\n",
    "plt.figure(figsize=(12, 5))\n",
    "\n",
    "# ---------------- RMSE Plot ----------------\n",
    "plt.subplot(1, 2, 1)\n",
    "bars1 = plt.bar(x - width/2, rmse_uber_values, width, label='Uber')\n",
    "bars2 = plt.bar(x + width/2, rmse_lyft_values, width, label='Lyft')\n",
    "\n",
    "plt.title('RMSE Comparison (Rain Impact)')\n",
    "plt.ylabel('RMSE')\n",
    "plt.xticks(x, models)\n",
    "plt.legend()\n",
    "\n",
    "# Add values\n",
    "for bar in bars1:\n",
    "    plt.text(bar.get_x() + bar.get_width()/2, bar.get_height(),\n",
    "             f'{bar.get_height():.3f}', ha='center', va='bottom')\n",
    "\n",
    "for bar in bars2:\n",
    "    plt.text(bar.get_x() + bar.get_width()/2, bar.get_height(),\n",
    "             f'{bar.get_height():.3f}', ha='center', va='bottom')\n",
    "\n",
    "# ---------------- R2 Plot ----------------\n",
    "plt.subplot(1, 2, 2)\n",
    "bars3 = plt.bar(x - width/2, r2_uber_values, width, label='Uber')\n",
    "bars4 = plt.bar(x + width/2, r2_lyft_values, width, label='Lyft')\n",
    "\n",
    "plt.title('R² Comparison (Rain Impact)')\n",
    "plt.ylabel('R² Score')\n",
    "plt.xticks(x, models)\n",
    "plt.legend()\n",
    "\n",
    "# Add values\n",
